import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        return None

    candidate_nodes = np.array([node for node in unvisited_nodes if node not in truck_nodes])
    if candidate_nodes.size == 0:
        candidate_nodes = unvisited_nodes.copy()

    next_node_distances = np.full(candidate_nodes.shape[0], np.inf)

    for i, node in enumerate(candidate_nodes):
        remaining_nodes = np.setdiff1d(candidate_nodes, [node])
        if remaining_nodes.size > 0:
            min_distance_to_next = np.min(distance_matrix[node, remaining_nodes])
            next_node_distances[i] = distance_matrix[current_node, node] + min_distance_to_next

    # Select the node with minimal cumulative distance to itself and the next closest node
    next_node = candidate_nodes[np.argmin(next_node_distances)]

    return next_node
